 23→// ─── Types ───
 24→
 25→interface DiffCanvasProps {
 26→  baseLayout: FlowmaidLayout;
 27→  compareLayout: FlowmaidLayout;
 28→  diffResult: DiffResult;
 29→  filters: DiffFilters;
 30→  onExit: () => void;
 31→  baseFileName: string;
 32→  compareFileName: string;
 33→  /** Flash target: set id + type + seq to trigger flash animation */
 34→  flashTarget?: { id: string; type: "node" | "edge"; seq: number } | null;
 35→  /** Opacity for the base flow elements (0-1), overlays are unaffected */
 36→  flowOpacity?: number;
 37→}
 38→
 39→interface DiffSingleCanvasProps {
 40→  layout: FlowmaidLayout;
 41→  diffResult: DiffResult;
 42→  filters: DiffFilters;
 43→  side: "base" | "compare";
 44→  fileName: string;
 45→  /** Ref to the other side's setViewport for direct sync */
 46→  otherSetViewportRef: React.MutableRefObject<((vp: Viewport) => void) | null>;
 47→  /** Ref where this side registers its own setViewport */
 48→  selfSetViewportRef: React.MutableRefObject<((vp: Viewport) => void) | null>;
 49→  /** Ref to prevent sync loops (per-side) */
 50→  isSyncingRef: React.MutableRefObject<boolean>;
 51→  onExit?: () => void;
 52→  /** Flash target for click-to-highlight */
 53→  flashTarget?: { id: string; type: "node" | "edge"; seq: number } | null;
 54→  /** Opacity for the base flow elements (0-1) */
 55→  flowOpacity?: number;
 56→}
 57→
 58→// ─── DiffSingleCanvas (one side of the side-by-side view) ───
 59→
 60→const DiffSingleCanvas = memo(function DiffSingleCanvas({
 61→  layout,
 62→  diffResult,
 63→  filters,
 64→  side,
 65→  fileName,
 66→  otherSetViewportRef,
 67→  selfSetViewportRef,
 68→  isSyncingRef,
 69→  flashTarget,
 70→  flowOpacity = 1,
 71→  onExit,
 72→}: DiffSingleCanvasProps) {
 73→  const { t } = useLocale();
 74→  const { setViewport } = useReactFlow();
 75→
 76→  // Register this side's setViewport so the other side can call it directly
 77→  selfSetViewportRef.current = setViewport;
 78→
 79→  // Build nodes/edges from layout (highlight is handled by DiffGlowOverlay)
 80→  const { displayNodes, displayEdges } = useMemo(
 81→    () => buildPlainNodesEdges(layout),
 82→    [layout],
 83→  );
 84→
 85→  // Sync viewport to the other side on every move (not just moveEnd)
 86→  const handleMove = useCallback(
 87→    (_event: unknown, vp: Viewport) => {
 88→      if (isSyncingRef.current) return;
 89→      const otherSetVp = otherSetViewportRef.current;
 90→      if (!otherSetVp) return;
 91→      isSyncingRef.current = true;
 92→      otherSetVp(vp);
 93→      // Reset syncing flag on next frame
 94→      requestAnimationFrame(() => {
 95→        isSyncingRef.current = false;
 96→      });
 97→    },
 98→    [otherSetViewportRef, isSyncingRef],
 99→  );
100→
101→  // Edge flash animation (node flash is handled by DiffGlowOverlay)
102→  const [flashingEdgeIds, setFlashingEdgeIds] = useState<Set<string>>(new Set());
103→  useEffect(() => {
104→    if (!flashTarget || flashTarget.type !== "edge") return;
105→    setFlashingEdgeIds(new Set([flashTarget.id]));
106→    const timer = setTimeout(() => setFlashingEdgeIds(new Set()), DIFF_FLASH_DURATION_MS);
107→    return () => clearTimeout(timer);
108→  }, [flashTarget]);
109→
110→  const finalEdges = useMemo(() => {
111→    if (flashingEdgeIds.size === 0) return displayEdges;
112→    return displayEdges.map((e) => {
113→      const isFlashing = flashingEdgeIds.has(e.id) || flashingEdgeIds.has(e.source);
114→      if (!isFlashing) return e;
115→      return { ...e, className: "diff-edge-flash" };
116→    });
117→  }, [displayEdges, flashingEdgeIds]);
118→
119→  return (
120→    <div className="h-full w-full relative diff-canvas-wrapper" style={{ "--diff-flow-opacity": flowOpacity } as React.CSSProperties}>
121→      <ReactFlow
122→        nodes={displayNodes}
123→        edges={finalEdges}
124→        nodeTypes={nodeTypes}
125→        edgeTypes={edgeTypes}
126→        nodesDraggable={false}
127→        nodesConnectable={false}
128→        elementsSelectable={false}
129→        connectOnClick={false}
130→        zoomOnScroll
131→        panOnDrag={[0, 1, 2]}
132→        fitView
133→        onMove={handleMove}
134→        proOptions={{ hideAttribution: true }}
135→      >
136→        <Background />
137→
138→        {/* Back button (left side only) */}
139→        {onExit && (
140→          <Panel position="top-left">
141→            <button
142→              onClick={onExit}
143→              className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-foreground/10 border border-border text-xs text-foreground backdrop-blur-sm hover:bg-foreground/15 cursor-pointer"
144→            >
145→              <ArrowLeft size={14} />
146→              {t("diffBack")}
147→            </button>
148→          </Panel>
149→        )}
150→        {/* File name label (right-aligned) */}
151→        <Panel position="top-right">
152→          <div className="px-2.5 py-1 rounded-md bg-foreground/10 border border-border text-xs text-foreground backdrop-blur-sm">
153→            {fileName}
154→          </div>
155→        </Panel>
156→
157→        {/* Diff glow overlay (shape-aware outer glow + inner shadow) */}
158→        <DiffGlowOverlay
159→          diffResult={diffResult}
160→          filters={filters}
161→          flashTarget={flashTarget}
162→          layout={layout}
163→          side={side}
164→        />
165→
166→        {/* Diff badge overlay */}
167→        <DiffBadgeOverlay
168→          diffResult={diffResult}
169→          filters={filters}
170→          layout={layout}
171→          side={side}
172→        />
173→      </ReactFlow>
174→    </div>
175→  );
176→});
