178→// ─── DiffCanvas (outer: side-by-side layout with two ReactFlowProviders) ───
179→
180→export const DiffCanvas = memo(function DiffCanvas({
181→  baseLayout,
182→  compareLayout,
183→  diffResult,
184→  filters,
185→  onExit,
186→  baseFileName,
187→  compareFileName,
188→  flashTarget,
189→  flowOpacity,
190→}: DiffCanvasProps) {
191→  // Separate syncing refs per side to avoid race conditions
192→  const baseSyncingRef = useRef(false);
193→  const compareSyncingRef = useRef(false);
194→
195→  // Refs to each side's setViewport for direct cross-side sync (no state/re-render)
