  1→"use client";
  2→
  3→import { memo, useMemo, useCallback, useRef, useState, useEffect } from "react";
  4→import {
  5→  ReactFlow,
  6→  ReactFlowProvider,
  7→  Panel,
  8→  Background,
  9→  useReactFlow,
 10→  type Viewport,
 11→} from "@xyflow/react";
 12→import { ArrowLeft } from "lucide-react";
 13→import { useLocale } from "@/lib/i18n/useLocale";
 14→import { nodeTypes } from "@/components/nodes/nodeTypes";
 15→import { edgeTypes } from "@/components/edges/edgeTypes";
 16→import type { FlowmaidLayout } from "@/lib/flowmaid/schema";
 17→import type { DiffResult, DiffFilters } from "@/lib/diff/types";
 18→import { DIFF_FLASH_DURATION_MS } from "@/lib/diff/types";
 19→import { buildPlainNodesEdges } from "@/lib/diff/buildDiffNodes";
 20→import { MIN_ZOOM, MAX_ZOOM } from "@/lib/constants";
 21→import { DiffBadgeOverlay } from "./DiffBadgeOverlay";
 22→import { DiffGlowOverlay } from "./DiffGlowOverlay";
 23→
 24→// ─── Types ───
 25→
 26→interface DiffCanvasProps {
 27→  baseLayout: FlowmaidLayout;
 28→  compareLayout: FlowmaidLayout;
 29→  diffResult: DiffResult;
 30→  filters: DiffFilters;
 31→  onExit: () => void;
 32→  baseFileName: string;
 33→  compareFileName: string;
 34→  /** Flash target: set id + type + seq to trigger flash animation */
 35→  flashTarget?: { id: string; type: "node" | "edge"; seq: number } | null;
 36→  /** Opacity for the base flow elements (0-1), overlays are unaffected */
 37→  flowOpacity?: number;
 38→}
 39→
 40→interface DiffSingleCanvasProps {
 41→  layout: FlowmaidLayout;
 42→  diffResult: DiffResult;
 43→  filters: DiffFilters;
 44→  side: "base" | "compare";
 45→  fileName: string;
 46→  /** Ref to the other side's setViewport for direct sync */
 47→  otherSetViewportRef: React.MutableRefObject<((vp: Viewport) => void) | null>;
 48→  /** Ref where this side registers its own setViewport */
 49→  selfSetViewportRef: React.MutableRefObject<((vp: Viewport) => void) | null>;
 50→  /** Ref to prevent sync loops (per-side) */
 51→  isSyncingRef: React.MutableRefObject<boolean>;
 52→  onExit?: () => void;
 53→  /** Flash target for click-to-highlight */
 54→  flashTarget?: { id: string; type: "node" | "edge"; seq: number } | null;
 55→  /** Opacity for the base flow elements (0-1) */
 56→  flowOpacity?: number;
 57→}
 58→
 59→// ─── DiffSingleCanvas (one side of the side-by-side view) ───
 60→
 61→const DiffSingleCanvas = memo(function DiffSingleCanvas({
 62→  layout,
 63→  diffResult,
 64→  filters,
 65→  side,
 66→  fileName,
 67→  otherSetViewportRef,
 68→  selfSetViewportRef,
 69→  isSyncingRef,
 70→  flashTarget,
 71→  flowOpacity = 1,
 72→  onExit,
 73→}: DiffSingleCanvasProps) {
 74→  const { t } = useLocale();
 75→  const { setViewport } = useReactFlow();
 76→
 77→  // Register this side's setViewport so the other side can call it directly
 78→  selfSetViewportRef.current = setViewport;
 79→
 80→  // Build nodes/edges from layout (highlight is handled by DiffGlowOverlay)
 81→  const { displayNodes, displayEdges } = useMemo(
 82→    () => buildPlainNodesEdges(layout),
 83→    [layout],
 84→  );
 85→
 86→  // Sync viewport to the other side on every move (not just moveEnd)
 87→  const handleMove = useCallback(
 88→    (_event: unknown, vp: Viewport) => {
 89→      if (isSyncingRef.current) return;
 90→      const otherSetVp = otherSetViewportRef.current;
 91→      if (!otherSetVp) return;
 92→      isSyncingRef.current = true;
 93→      otherSetVp(vp);
 94→      // Reset syncing flag on next frame
 95→      requestAnimationFrame(() => {
 96→        isSyncingRef.current = false;
 97→      });
 98→    },
 99→    [otherSetViewportRef, isSyncingRef],
100→  );
101→
102→  // Edge flash animation (node flash is handled by DiffGlowOverlay)
103→  const [flashingEdgeIds, setFlashingEdgeIds] = useState<Set<string>>(new Set());
104→  useEffect(() => {
105→    if (!flashTarget || flashTarget.type !== "edge") return;
106→    setFlashingEdgeIds(new Set([flashTarget.id]));
107→    const timer = setTimeout(() => setFlashingEdgeIds(new Set()), DIFF_FLASH_DURATION_MS);
108→    return () => clearTimeout(timer);
109→  }, [flashTarget]);
110→
111→  const finalEdges = useMemo(() => {
112→    if (flashingEdgeIds.size === 0) return displayEdges;
113→    return displayEdges.map((e) => {
114→      const isFlashing = flashingEdgeIds.has(e.id) || flashingEdgeIds.has(e.source);
115→      if (!isFlashing) return e;
116→      return { ...e, className: "diff-edge-flash" };
117→    });
118→  }, [displayEdges, flashingEdgeIds]);
119→
120→  return (
121→    <div className="h-full w-full relative diff-canvas-wrapper" style={{ "--diff-flow-opacity": flowOpacity } as React.CSSProperties}>
122→      <ReactFlow
123→        nodes={displayNodes}
124→        edges={finalEdges}
125→        nodeTypes={nodeTypes}
126→        edgeTypes={edgeTypes}
127→        nodesDraggable={false}
128→        nodesConnectable={false}
129→        elementsSelectable={false}
130→        connectOnClick={false}
131→        minZoom={MIN_ZOOM}
132→        maxZoom={MAX_ZOOM}
133→        panOnScroll
134→        zoomOnScroll={false}
135→        zoomActivationKeyCode="Control"
136→        panOnDrag={[0, 1, 2]}
137→        fitView
138→        onMove={handleMove}
139→        proOptions={{ hideAttribution: true }}
140→      >
141→        <Background />
142→
143→        {/* Back button (left side only) */}
144→        {onExit && (
145→          <Panel position="top-left">
146→            <button
147→              onClick={onExit}
148→              className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-foreground/10 border border-border text-xs text-foreground backdrop-blur-sm hover:bg-foreground/15 cursor-pointer"
149→            >
150→              <ArrowLeft size={14} />
151→              {t("diffBack")}
152→            </button>
153→          </Panel>
154→        )}
155→        {/* File name label (right-aligned) */}
156→        <Panel position="top-right">
157→          <div className="px-2.5 py-1 rounded-md bg-foreground/10 border border-border text-xs text-foreground backdrop-blur-sm">
158→            {fileName}
159→          </div>
160→        </Panel>
161→
162→        {/* Diff glow overlay (shape-aware outer glow + inner shadow) */}
163→        <DiffGlowOverlay
164→          diffResult={diffResult}
165→          filters={filters}
166→          flashTarget={flashTarget}
167→          layout={layout}
168→          side={side}
169→        />
170→
171→        {/* Diff badge overlay */}
172→        <DiffBadgeOverlay
173→          diffResult={diffResult}
174→          filters={filters}
175→          layout={layout}
176→          side={side}
177→        />
178→      </ReactFlow>
179→    </div>
180→  );
181→});
182→
183→// ─── DiffCanvas (outer: side-by-side layout with two ReactFlowProviders) ───
184→
185→export const DiffCanvas = memo(function DiffCanvas({
186→  baseLayout,
187→  compareLayout,
188→  diffResult,
189→  filters,
190→  onExit,
191→  baseFileName,
192→  compareFileName,
193→  flashTarget,
194→  flowOpacity,
195→}: DiffCanvasProps) {
196→  // Separate syncing refs per side to avoid race conditions
197→  const baseSyncingRef = useRef(false);
198→  const compareSyncingRef = useRef(false);
199→
200→  // Refs to each side's setViewport for direct cross-side sync (no state/re-render)
201→  const baseSetViewportRef = useRef<((vp: Viewport) => void) | null>(null);
202→  const compareSetViewportRef = useRef<((vp: Viewport) => void) | null>(null);
203→
204→  return (
205→    <div className="flex h-full w-full">
206→      {/* Left: Base canvas */}
207→      <div className="flex-1 h-full border-r border-border">
208→        <ReactFlowProvider>
209→          <DiffSingleCanvas
210→            layout={baseLayout}
211→            diffResult={diffResult}
212→            filters={filters}
213→            side="base"
214→            fileName={baseFileName}
215→            otherSetViewportRef={compareSetViewportRef}
216→            selfSetViewportRef={baseSetViewportRef}
